
.slider-container {
  margin-top: 2rem;
  position: relative;
  white-space: nowrap;
  width: 100%;
  text-align: center;
  overflow: hidden;
  z-index: 1;
}
.slider-wrapper {
  box-sizing: content-box;
  display: -webkit-box;
  display: -ms-flexbox;
  display: flex;
  position: relative;
  transition-property: -webkit-transform;
  transition-property: transform;
  transition-property: transform, -webkit-transform;
  z-index: 1;
  -ms-flex-pack: distribute;
      justify-content: space-around;
  width: 300%;
}
.slider-item {
  -webkit-box-flex: 0;
      -ms-flex: none;
          flex: none;
  position: relative;
  width: 33.33%;
}
.slider-item-p {
  width: 10.8rem;
  height: 15.48rem;
  margin: 0 auto;
}
.slider-item-0 {
  background: url('~@/assets/image/1.png') no-repeat center;
  background-size: 100%;
}
.slider-item-1 {
  background: url('~@/assets/image/2.png') no-repeat center;
  background-size: 100%;
}
.slider-item-2 {
  background: url('~@/assets/image/3.png') no-repeat center;
  background-size: 100%;
}
@media screen and (-webkit-min-device-pixel-ratio: 2) {
.slider-item-0 {
    background: url('~@/assets/image/1-2x.png') no-repeat center;
    background-size: 100%;
}
.slider-item-1 {
    background: url('~@/assets/image/2-2x.png') no-repeat center;
    background-size: 100%;
}
.slider-item-2 {
    background: url('~@/assets/image/3-2x.png') no-repeat center;
    background-size: 100%;
}
}



