
.hmb-loading {
  transition: opacity .2s linear;
}
.hmb-loading-wrapper {
  position: fixed;
  left: 50%;
  top: 50%;
  -webkit-transform: translate(-50%, -50%);
          transform: translate(-50%, -50%);
  border-radius: 5px;
  background: rgba(0, 0, 0, 0.7);
  color: white;
  box-sizing: border-box;
  text-align: center;
}
.hmb-loading-text {
  display: block;
  color: #fff;
  text-align: center;
  font-size: 16px;
}
.hmb-loading-spin {
  display: inline-block;
  text-align: center;
}
.hmb-loading-mask {
  position: fixed;
  left: 0;
  top: 0;
  width: 100%;
  height: 100%;
  opacity: 0;
  background: transparent;
}
.hmb-loading-enter-active,
.hmb-loading-leave-active {
  transition: opacity 0.5s;
}
.hmb-loading-enter,
.hmb-loading-leave-active {
  opacity: 0;
}



