
.button-wrap {
  position: relative;
  height: 1.92rem;
  line-height: 1.92rem;
  text-align: center;
  cursor: pointer;
  background: #fff;
  box-shadow: 0 1px 0 0 #eee, inset 0 1px 0 0 #eee;
}
.button-wrap button {
  border: none;
  color: #3487e2;
  width: 100%;
  height: 100%;
  font-size: 0.68rem;
  background: #fff;
}
.button-wrap button:active {
  background: #F8F8F8;
}
.button-wrap button.disabled {
  color: #cccccc;
}



