/* reset */
body,
div,
dl,
dt,
dd,
ul,
ol,
li,
h1,
h2,
h3,
h4,
h5,
h6,
pre,
code,
form,
fieldset,
legend,
input,
button,
textarea,
p,
blockquote,
th,
td,
section,
article,
aside,
header,
footer,
nav,
dialog,
figure,
hgroup {
  margin: 0;
  padding: 0;
}
input,
select,
textarea {
  font-size: 100%;
  -webkit-tap-highlight-color: rgba(255, 0, 0, 0);
  -webkit-user-select: auto;
  -webkit-appearance: none;
}
table {
  border-collapse: collapse;
  border-spacing: 0;
}
fieldset,
img {
  border: 0;
}
caption,
th {
  text-align: left;
}
h1,
h2,
h3,
h4,
h5,
h6 {
  font-size: 100%;
  font-weight: 500;
}
ul,
ol,
li {
  list-style: none;
}
em,
i {
  font-style: normal;
}
del {
  text-decoration: line-through;
}
address,
caption,
cite,
code,
dfn,
em,
th,
var {
  font-style: normal;
  font-weight: 500;
}
img {
  border: 0;
  max-width: 100%;
}
input,
img {
  vertical-align: middle;
}
input:focus,
a:focus {
  outline: none;
}
a {
  color: #333333;
  text-decoration: none;
}
a:active {
  opacity: .7;
}
* {
  outline: none;
  -webkit-tap-highlight-color: rgba(0, 0, 0, 0);
  -webkit-box-sizing: border-box;
  -webkit-user-select: none;
}
html {
  -webkit-text-size-adjust: none;
  overflow-y: scroll;
}
/*
  rem方式，750px 为高保真基准，原高保真大小除以基数50，即 10px/50 = 0.2rem，以此类推,字体还是 px
 */
html {
  font-size: 50px;
}
body {
  font-size: 24px;
}
@media screen and (min-width: 240px) {
html {
    font-size: 16px;
}
body {
    font-size: 12px;
}
}
@media screen and (min-width: 280px) {
html {
    font-size: 18.666666667px;
}
body {
    font-size: 12px;
}
}
@media screen and (min-width: 320px) {
html {
    font-size: 21.333333333333332px;
}
body {
    font-size: 12px;
}
}
@media screen and (min-width: 360px) {
html {
    font-size: 24px;
}
body {
    font-size: 12px;
}
}
@media screen and (min-width: 375px) {
html {
    font-size: 25px;
}
body {
    font-size: 12px;
}
}
@media screen and (min-width: 384px) {
html {
    font-size: 25.6px;
}
body {
    font-size: 14px;
}
}
@media screen and (min-width: 400px) {
html {
    font-size: 26.666666666666668px;
}
body {
    font-size: 14px;
}
}
@media screen and (min-width: 414px) {
html {
    font-size: 27.6px;
}
body {
    font-size: 14px;
}
}
@media screen and (min-width: 424px) {
html {
    font-size: 28.266666666666667px;
}
body {
    font-size: 14px;
}
}
@media screen and (min-width: 480px) {
html {
    font-size: 32px;
}
body {
    font-size: 15.36px;
}
}
@media screen and (min-width: 540px) {
html {
    font-size: 36px;
}
body {
    font-size: 17.28px;
}
}
@media screen and (min-width: 720px) {
html {
    font-size: 48px;
}
body {
    font-size: 23.04px;
}
}
@media screen and (min-width: 750px) {
html {
    font-size: 50px;
}
body {
    font-size: 24px;
}
}
body {
  background: #fff;
  line-height: 1.5;
  font-family: -apple-system-font, "Helvetica Neue", "PingFang SC", "Hiragino Sans GB", "Microsoft YaHei", sans-serif;
}
.email-bind-header ul {
  display: -webkit-box;
  display: -ms-flexbox;
  display: flex;
  width: 100%;
  background: #fff;
}
.email-bind-header ul li {
  border-bottom: 2px solid transparent;
  width: 50%;
  height: 1.6rem;
  line-height: 1.6rem;
  text-align: center;
}
.email-bind-header ul li.active {
  border-color: #fcb058;
  color: #fcb058;
}
.article {
  margin-top: 0.6rem;
}
.article h4 {
  padding: 0 0.6rem;
  font-size: 0.56rem;
  color: #999999;
  letter-spacing: 0px;
  line-height: 0.56rem;
  text-align: left;
  margin-bottom: 0.6rem;
}
.article-istitle .input-left {
  -webkit-box-flex: 0;
      -ms-flex: 0 0 3.52rem;
          flex: 0 0 3.52rem;
}
.footer {
  margin-top: 0.6rem;
}
.footer-carousel {
  margin-top: 0;
  position: fixed;
  bottom: 0;
  left: 0;
  padding: 0.6rem;
  width: 100%;
  background: #fff;
  z-index: 20;
}
.footer-carousel .button-wrap button {
  color: #fff;
  background: #fcb058;
  border-radius: 0.2rem;
}



